Contenido
-- SGCE · modo prueba · SQL reescrito e idempotente -- Ejecutar DESPUÉS de importar la base principal del sistema.
-- Este script no elimina datos existentes.
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
CREATE TABLE IF NOT EXISTS sgce_logs (   id INT AUTO_INCREMENT PRIMARY KEY,   user_id INT NULL,   accion VARCHAR(80) NOT NULL,   modulo VARCHAR(80) NOT NULL,   entidad_id INT NULL,   detalle TEXT NULL,   ip VARCHAR(64) NULL,   user_agent VARCHAR(255) NULL,   created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,   INDEX idx_logs_modulo_fecha (modulo, created_at),
  INDEX idx_logs_usuario_fecha (user_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS casos_historial (   id INT AUTO_INCREMENT PRIMARY KEY,   caso_id INT NOT NULL,   tipo_evento VARCHAR(60) NOT NULL,   descripcion TEXT NULL,   user_id INT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_caso_historial (caso_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS casos_evidencias (   id INT AUTO_INCREMENT PRIMARY KEY,   caso_id INT NOT NULL,   nombre_archivo VARCHAR(255) NOT NULL,   ruta_archivo VARCHAR(255) NOT NULL,   mime_type VARCHAR(120) NULL,   tamano_bytes BIGINT NULL,   subido_por INT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_casos_evidencias (caso_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS casos_accesos (   id INT AUTO_INCREMENT PRIMARY KEY,   caso_id INT NOT NULL,   user_id INT NULL,   accion VARCHAR(60) NOT NULL DEFAULT 'ver',   created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_casos_accesos (caso_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS reglamento_versiones (   id INT AUTO_INCREMENT PRIMARY KEY,
  colegio_id INT NOT NULL,   titulo VARCHAR(180) NOT NULL,   contenido_largo LONGTEXT NULL,   estado ENUM('vigente','historico','borrador') NOT NULL DEFAULT 'borrador',   creado_por INT NULL,   created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,   updated_at DATETIME NULL DEFAULT NULL,
  INDEX idx_reglamento_versiones (colegio_id, estado, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS reglamento_estructura (   id INT AUTO_INCREMENT PRIMARY KEY,   reglamento_id INT NOT NULL,   tipo VARCHAR(50) NOT NULL,   categoria VARCHAR(120) NULL,   titulo VARCHAR(180) NULL,   contenido TEXT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_reglamento_estructura (reglamento_id, tipo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
SET FOREIGN_KEY_CHECKS = 1;
