INSERT INTO denuncias_expediente (     denuncia_id,     estado_flujo,     fecha_inicio_investigacion,     fecha_ultima_actuacion,     created_at,     updated_at ) SELECT
    d.id,
    CASE
        WHEN d.estado = 'cerrado' THEN 'cerrado'
        WHEN d.estado = 'en_proceso' THEN 'en_investigacion'
        ELSE 'ingresado'
    END,
    NOW(),
    NOW(),
    NOW(),
    NOW()
FROM denuncias d
LEFT JOIN denuncias_expediente de ON de.denuncia_id = d.id WHERE de.id IS NULL;
