INSERT INTO medidas_preventivas (     denuncia_id,     medidas_preventivas,     fecha_seguimiento,     tipo_comunicacion,     fecha_comunicacion,     notas_comunicacion,     estado_cumplimiento,     created_at,     updated_at ) SELECT
