    if ($caso) {         segAudit($pdo, 'ver', $denunciaId);
        $stmtPart = $pdo->prepare("
            SELECT dp.*,
                   COALESCE(
                      NULLIF(TRIM(CONCAT(
                        COALESCE(a.apellido_paterno, doc.apellido_paterno, apo.ap                         COALESCE(a.nombres, doc.nombres, apo.nombres, '')
                      )), ''),
                      NULLIF(dp.nombre_referencial, ''),
                      'N/N'
                   ) AS nombre_resuelto
            FROM denuncia_participantes dp
            LEFT JOIN alumnos a
                ON a.run = dp.alumno_run
            LEFT JOIN docentes doc
                ON doc.run = dp.persona_run
               AND dp.tipo_persona = 'docente'
            LEFT JOIN apoderados apo
                ON apo.run = dp.persona_run
               AND dp.tipo_persona = 'apoderado'             WHERE dp.denuncia_id = ?
            ORDER BY FIELD(dp.condicion,'victima','denunciante','testigo','denunc
        ");
        $stmtPart->execute([$denunciaId]);         $participantes = $stmtPart->fetchAll(PDO::FETCH_ASSOC);
        $stmtMedPrev = $pdo->prepare("
            SELECT *
            FROM medidas_preventivas             WHERE denuncia_id = ?
            LIMIT 1
        ");
        $stmtMedPrev->execute([$denunciaId]);
        $medidaPrev = $stmtMedPrev->fetch(PDO::FETCH_ASSOC) ?: null;
        $stmtPlan = $pdo->prepare("
            SELECT *
            FROM seguimiento_medidas             WHERE denuncia_id = ?
            ORDER BY id ASC
        ");
        $stmtPlan->execute([$denunciaId]);
        $planMedidas = $stmtPlan->fetchAll(PDO::FETCH_ASSOC);
        $stmtAv = $pdo->prepare("
            SELECT sa.*,
                   COALESCE(u.nombre, 'Sistema') AS creado_por_nombre
            FROM seguimiento_avances sa
            LEFT JOIN usuarios u ON u.id = sa.created_by             WHERE sa.denuncia_id = ?
            ORDER BY sa.id DESC
        ");
        $stmtAv->execute([$denunciaId]);
        $avances = $stmtAv->fetchAll(PDO::FETCH_ASSOC);
        // Si no hay plan por participante, lo crea como base para no dejar el ca         if (empty($planMedidas) && !empty($participantes)) {             try {
                $pdo->beginTransaction();
                $stmtInsertPlan = $pdo->prepare("                     INSERT INTO seguimiento_medidas (                         denuncia_id, participante_run, participante_nombre, condi                     ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP, CURRENT_
                ");
                foreach ($participantes as $p) {
                    $run = $p['persona_run'] ?: $p['alumno_run'];
                    $nombre = $p['nombre_resuelto'] ?: 'N/N';
                    $stmtInsertPlan->execute([
                        $denunciaId,
                        $run ?: null,
                        $nombre,
                        $p['condicion'] ?? null,                         null,                         'pendiente',                         null,                         null
                    ]);
                }
                $pdo->commit();
                $stmtPlan->execute([$denunciaId]);
                $planMedidas = $stmtPlan->fetchAll(PDO::FETCH_ASSOC);
            } catch (Throwable $e) {                 if ($pdo->inTransaction()) {
                    $pdo->rollBack();
                }
            }
        }
    }
}
