<script> (function() {   const rows = document.querySelectorAll('tr[data-id]');   const inputQ = document.querySelector('input[name="q"]');   const selEstado = document.querySelector('select[name="estado"]');   const selGrav = document.querySelector('select[name="grav"]');
  function filtrarTabla() {     if (!rows.length || !inputQ || !selEstado || !selGrav) return;     const q = (inputQ.value || '').toLowerCase().trim();     const estado = selEstado.value;     const grav = selGrav.value;
    rows.forEach(row => {       const txt = (row.dataset.search || '').toLowerCase();       const okQ = !q || txt.includes(q);       const okE = !estado || row.dataset.estado === estado;       const okG = !grav || row.dataset.grav === grav;       row.style.display = (okQ && okE && okG) ? '' : 'none';
    });   }
  if (inputQ) inputQ.addEventListener('input', filtrarTabla);   if (selEstado) selEstado.addEventListener('change', filtrarTabla);   if (selGrav) selGrav.addEventListener('change', filtrarTabla);
})();
</script>
