SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
-- =========================================================
-- 1) TABLA COLEGIOS
-- ========================================================= CREATE TABLE IF NOT EXISTS colegios (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     rbd VARCHAR(20) NOT NULL,     rut_entidad VARCHAR(20) DEFAULT NULL,     nombre VARCHAR(255) NOT NULL,     dependencia VARCHAR(50) DEFAULT NULL,     comuna VARCHAR(120) DEFAULT NULL,     region VARCHAR(120) DEFAULT NULL,     direccion VARCHAR(255) DEFAULT NULL,     telefono VARCHAR(50) DEFAULT NULL,     email VARCHAR(150) DEFAULT NULL,     proyecto_educativo TEXT DEFAULT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_colegios_rbd (rbd)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
-- =========================================================
-- 2) TABLA CURSOS
-- ========================================================= CREATE TABLE IF NOT EXISTS cursos (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     colegio_id INT UNSIGNED NOT NULL,     codigo VARCHAR(30) NOT NULL,     nombre VARCHAR(120) NOT NULL,     nivel VARCHAR(30) NOT NULL,
    jornada VARCHAR(30) DEFAULT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_cursos_colegio_codigo (colegio_id, codigo),
    KEY idx_cursos_colegio (colegio_id),
    CONSTRAINT fk_cursos_colegio         FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
-- =========================================================
-- 3) TABLA ALUMNO_APODERADO
-- ========================================================= CREATE TABLE IF NOT EXISTS alumno_apoderado (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     alumno_id INT UNSIGNED NOT NULL,     apoderado_id INT UNSIGNED NOT NULL,     tipo_relacion VARCHAR(50) DEFAULT NULL,     es_titular TINYINT(1) NOT NULL DEFAULT 0,     puede_retirar TINYINT(1) NOT NULL DEFAULT 0,     recibe_notificaciones TINYINT(1) NOT NULL DEFAULT 1,     vive_con_estudiante TINYINT(1) NOT NULL DEFAULT 0,     observacion VARCHAR(255) DEFAULT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_alumno_apoderado (alumno_id, apoderado_id),
    KEY idx_alumno_apoderado_alumno (alumno_id),
    KEY idx_alumno_apoderado_apoderado (apoderado_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
-- =========================================================
-- 4) COLEGIO BASE
--    Ajusta el RBD y datos si quieres usar los tuyos reales
-- ========================================================= INSERT INTO colegios (     rbd,     rut_entidad,     nombre,     dependencia,     comuna,     region,     direccion,     telefono,     email,     activo ) VALUES (
    '99999',
    '76.000.000-0',
    'Sistema Gestiona - Colegio Demo',
    'particular_subvencionado',
    'Santa Cruz',
    'O’Higgins',
    'Dirección Demo 123',
    '+56 9 0000 0000',
    'contacto@gestiona.local',
    1
)
ON DUPLICATE KEY UPDATE     rut_entidad = VALUES(rut_entidad),     nombre = VALUES(nombre),     dependencia = VALUES(dependencia),     comuna = VALUES(comuna),     region = VALUES(region),     direccion = VALUES(direccion),     telefono = VALUES(telefono),     email = VALUES(email),     activo = VALUES(activo);
-- ========================================================= -- 5) CURSOS BASE
--    Se insertan buscando el colegio por RBD
-- ========================================================= INSERT INTO cursos (     colegio_id,     codigo,     nombre,     nivel,     jornada,     activo ) SELECT
    c.id,
    t.codigo,
    t.nombre,
    t.nivel,
    t.jornada,
    t.activo
FROM colegios c
JOIN (
    SELECT '5BAS-A' AS codigo, '5° Básico A' AS nombre, 'basica' AS nivel, 'mańan
    UNION ALL
    SELECT '7BAS-A', '7° Básico A', 'basica', 'mańana', 1
    UNION ALL
    SELECT '1MED-A', '1° Medio A', 'media', 'mańana', 1     UNION ALL
    SELECT '2MED-A', '2° Medio A', 'media', 'mańana', 1
) t
WHERE c.rbd = '99999' ON DUPLICATE KEY UPDATE     nombre = VALUES(nombre),     nivel = VALUES(nivel),     jornada = VALUES(jornada),     activo = VALUES(activo);
-- =========================================================
-- 6) ÍNDICES Y FK PARA ALUMNO_APODERADO
--    Solo si existen tablas alumnos y apoderados
-- =========================================================
-- FK alumno_id -> alumnos(id)
SET @alumnos_exists := (
    SELECT COUNT(*)
    FROM information_schema.tables
    WHERE table_schema = DATABASE()
      AND table_name = 'alumnos'
);
SET @apoderados_exists := (
    SELECT COUNT(*)
    FROM information_schema.tables
    WHERE table_schema = DATABASE()       AND table_name = 'apoderados'
);
-- Agregar FK a alumnos si existe tabla alumnos
SET @sql := IF(
    @alumnos_exists > 0,
    'ALTER TABLE alumno_apoderado
        ADD CONSTRAINT fk_alumno_apoderado_alumno
        FOREIGN KEY (alumno_id) REFERENCES alumnos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE',
    'SELECT "Tabla alumnos no existe todavía; FK omitida por ahora."'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
-- Agregar FK a apoderados si existe tabla apoderados
SET @sql := IF(
    @apoderados_exists > 0,
    'ALTER TABLE alumno_apoderado
        ADD CONSTRAINT fk_alumno_apoderado_apoderado
        FOREIGN KEY (apoderado_id) REFERENCES apoderados(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE',
    'SELECT "Tabla apoderados no existe todavía; FK omitida por ahora."'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
SET FOREIGN_KEY_CHECKS = 1;
Qué hace bien este bloque
colegios
usa rbd como identificador de negocio único, mantiene id técnico para relaciones internas, deja rut_entidad aparte.
cursos
no depende de que el colegio tenga id = 1 , busca el colegio por rbd , evita duplicados con UNIQUE (colegio_id, codigo) .
alumno_apoderado
crea la estructura correcta, permite titular, retiro, notificaciones, convivencia con el estudiante, y solo intenta agregar claves foráneas si las tablas alumnos y apoderados ya existen.
