CREATE TABLE IF NOT EXISTS alumnos (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     colegio_id INT UNSIGNED NOT NULL,     curso_id INT UNSIGNED DEFAULT NULL,     run VARCHAR(20) NOT NULL,     apellido_paterno VARCHAR(80) NOT NULL,     apellido_materno VARCHAR(80) DEFAULT NULL,     nombres VARCHAR(120) NOT NULL,     fecha_nacimiento DATE DEFAULT NULL,     genero VARCHAR(30) DEFAULT NULL,     direccion VARCHAR(255) DEFAULT NULL,     telefono VARCHAR(50) DEFAULT NULL,     email VARCHAR(150) DEFAULT NULL,     observacion VARCHAR(255) DEFAULT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_alumnos_run (run),
    KEY idx_alumnos_colegio (colegio_id),
    KEY idx_alumnos_curso (curso_id),
    CONSTRAINT fk_alumnos_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_alumnos_curso
        FOREIGN KEY (curso_id) REFERENCES cursos(id)
        ON DELETE SET NULL
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

Paso 2: tabla apoderados
CREATE TABLE IF NOT EXISTS apoderados (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     colegio_id INT UNSIGNED NOT NULL,     run VARCHAR(20) NOT NULL,     apellido_paterno VARCHAR(80) NOT NULL,     apellido_materno VARCHAR(80) DEFAULT NULL,     nombres VARCHAR(120) NOT NULL,     telefono VARCHAR(50) DEFAULT NULL,     telefono_secundario VARCHAR(50) DEFAULT NULL,     email VARCHAR(150) DEFAULT NULL,     direccion VARCHAR(255) DEFAULT NULL,     observacion VARCHAR(255) DEFAULT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_apoderados_run (run),
    KEY idx_apoderados_colegio (colegio_id),
    CONSTRAINT fk_apoderados_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

Paso 3: agregar FK a alumno_apoderado
Ahora que ya existirán las tablas maestras:
