Paso 4: tabla matriculas
CREATE TABLE IF NOT EXISTS matriculas (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     alumno_id INT UNSIGNED NOT NULL,     colegio_id INT UNSIGNED NOT NULL,     curso_id INT UNSIGNED NOT NULL,     anio INT NOT NULL,     fecha_matricula DATE DEFAULT NULL,     estado VARCHAR(30) NOT NULL DEFAULT 'vigente',     observacion VARCHAR(255) DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_matricula_anual (alumno_id, anio),
    KEY idx_matriculas_colegio (colegio_id),
    KEY idx_matriculas_curso (curso_id),
    CONSTRAINT fk_matriculas_alumno
        FOREIGN KEY (alumno_id) REFERENCES alumnos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_matriculas_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_matriculas_curso
        FOREIGN KEY (curso_id) REFERENCES cursos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
