SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
-- =========================================================
-- 1) ROLES
-- ========================================================= CREATE TABLE IF NOT EXISTS roles (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     codigo VARCHAR(50) NOT NULL UNIQUE,     nombre VARCHAR(100) NOT NULL,     descripcion VARCHAR(255) NULL,     activo TINYINT(1) DEFAULT 1
);
-- =========================================================
-- 2) PERMISOS
-- ========================================================= CREATE TABLE IF NOT EXISTS permisos (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     codigo VARCHAR(100) NOT NULL UNIQUE,     nombre VARCHAR(150) NOT NULL,     modulo VARCHAR(100) NOT NULL
);
-- =========================================================
-- 3) RELACIÓN ROL-PERMISO
-- ========================================================= CREATE TABLE IF NOT EXISTS rol_permiso (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     rol_id INT UNSIGNED NOT NULL,     permiso_id INT UNSIGNED NOT NULL,
    UNIQUE KEY uq_rol_permiso (rol_id, permiso_id),
    FOREIGN KEY (rol_id) REFERENCES roles(id) ON DELETE CASCADE,
    FOREIGN KEY (permiso_id) REFERENCES permisos(id) ON DELETE CASCADE
);
-- =========================================================
-- 4) USUARIOS
-- ========================================================= CREATE TABLE IF NOT EXISTS usuarios (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     rol_id INT UNSIGNED NOT NULL,     run VARCHAR(20) NOT NULL,     nombre VARCHAR(150) NOT NULL,     email VARCHAR(150) NOT NULL,     password_hash VARCHAR(255) NOT NULL,     activo TINYINT(1) DEFAULT 1,     ultimo_acceso DATETIME NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY uq_usuario_email (email),
    FOREIGN KEY (colegio_id) REFERENCES colegios(id) ON DELETE CASCADE,
    FOREIGN KEY (rol_id) REFERENCES roles(id) ON DELETE CASCADE
);
-- =========================================================
-- 5) BITÁCORA DEL SISTEMA
-- ========================================================= CREATE TABLE IF NOT EXISTS logs_sistema (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NULL,     usuario_id INT UNSIGNED NULL,     modulo VARCHAR(100) NOT NULL,     accion VARCHAR(100) NOT NULL,     entidad VARCHAR(100) NULL,     entidad_id INT NULL,     descripcion TEXT NULL,     ip VARCHAR(50) NULL,     user_agent VARCHAR(255) NULL,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (colegio_id) REFERENCES colegios(id) ON DELETE SET NULL,
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL
);
-- =========================================================
-- 6) LOG DE IA (TRAZABILIDAD)
-- ========================================================= CREATE TABLE IF NOT EXISTS logs_ia (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     caso_id INT NULL,     usuario_id INT NULL,     accion VARCHAR(100),     input_text TEXT,     output_text TEXT,     decision_usuario TEXT,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
