        $base = iconv('UTF-8', 'ASCII//TRANSLIT//IGNORE', $base) ?: $base;
        $base = preg_replace('/[^A-Za-z0-9_\-]+/', '_', $base);
        $base = trim((string)$base, '_-');         $base = $base !== '' ? $base : 'archivo';
        return $base . ($ext !== '' ? '.' . $ext : '');
