    {         self::startSession();         return $_SESSION['user'] ?? null;
    }
    public static function id(): ?int
    {         self::startSession();         return isset($_SESSION['user']['id']) ? (int)$_SESSION['user']['id'] : nu
    }
    public static function logout(): void
    {         self::startSession();         $_SESSION = [];
        if (ini_get('session.use_cookies')) {             $params = session_get_cookie_params();             setcookie(                 session_name(),                 '',                 time() - 42000,                 $params['path'],
                $params['domain'],
