        $pdo = self::pdo();
        $stmt = $pdo->prepare("             SELECT COUNT(*)
            FROM rol_permiso rp
            INNER JOIN permisos p ON p.id = rp.permiso_id             WHERE rp.rol_id = ?
              AND p.codigo = ?
            LIMIT 1
        ");
        $stmt->execute([
            (int)$_SESSION['user']['rol_id'],
            $permisoCodigo
        ]);
        return (int)$stmt->fetchColumn() > 0;
    }     public static function requireLogin(): void     {         if (!self::check()) {             header('Location: ' . APP_URL . '/public/login.php');             exit;         }
    }
}
