CREATE TABLE roles (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     codigo VARCHAR(50) NOT NULL UNIQUE,     nombre VARCHAR(100) NOT NULL,     descripcion VARCHAR(255) NULL,     activo TINYINT(1) NOT NULL DEFAULT 1
