<?php declare(strict_types=1);
final class Auth
{     public static function startSession(): void
    {         if (session_status() === PHP_SESSION_NONE) {
            $secure = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off');
            session_set_cookie_params([
                'lifetime' => 0,
                'path' => '/',
                'domain' => '',
                'secure' => $secure,                 'httponly' => true,
                'samesite' => 'Lax',
            ]);
            session_start();
        }     }
    private static function pdo(): PDO
    {         return DB::conn();
    }
    public static function attempt(string $email, string $password): bool
    {
        self::startSession();         $pdo = self::pdo();
        $stmt = $pdo->prepare("
            SELECT
                u.id,
                u.nombre,
                u.email,
                u.password_hash,
                u.activo,
                u.colegio_id,
                u.rol_id             FROM usuarios u             WHERE u.email = ?
            LIMIT 1
        ");
        $stmt->execute([$email]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);
        if (!$user) {             return false;
        }
        if ((int)$user['activo'] !== 1) {             return false;
        }
        if (!password_verify($password, (string)$user['password_hash'])) {             return false;
        }         session_regenerate_id(true);
        $_SESSION['user'] = [
            'id' => (int)$user['id'],
            'nombre' => (string)$user['nombre'],
            'email' => (string)$user['email'],
            'colegio_id' => (int)$user['colegio_id'],
            'rol_id' => (int)$user['rol_id'],
        ];
        return true;     }
    public static function check(): bool
    {         self::startSession();         return !empty($_SESSION['user']['id']);
    }
    public static function user(): ?array
    {         self::startSession();         return $_SESSION['user'] ?? null;
    }
    public static function logout(): void
    {         self::startSession();         $_SESSION = [];
        if (ini_get('session.use_cookies')) {             $params = session_get_cookie_params();             setcookie(                 session_name(),                 '',                 time() - 42000,                 $params['path'],
                $params['domain'],
                $params['secure'],
                $params['httponly']
            );         }
        session_destroy();
    }
    public static function requireLogin(): void
    {         if (!self::check()) {             header('Location: ' . APP_URL . '/public/login.php');             exit;         }
    }
}
Etapa 4.6: core/CSRF.php
Crea este archivo:
PHP
<?php declare(strict_types=1);
final class CSRF
{     public static function token(): string
    {         Auth::startSession();
        if (empty($_SESSION['_csrf']) || !is_string($_SESSION['_csrf'])) {
            $_SESSION['_csrf'] = bin2hex(random_bytes(32));
        }
        return $_SESSION['_csrf'];
    }
    public static function field(): string
    {         return '<input type="hidden" name="_token" value="' .             htmlspecialchars(self::token(), ENT_QUOTES, 'UTF-8') .
            '">';     }
    public static function validate(?string $token): bool
    {
        Auth::startSession();
        $sessionToken = $_SESSION['_csrf'] ?? '';
        return is_string($token)             && $token !== ''
            && is_string($sessionToken)
            && $sessionToken !== ''
            && hash_equals($sessionToken, $token);
    }
    public static function regenerate(): void
    {
        Auth::startSession();
        $_SESSION['_csrf'] = bin2hex(random_bytes(32));
    }
}
