CREATE TABLE IF NOT EXISTS caso_historial (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     caso_id INT UNSIGNED NOT NULL,     tipo_evento VARCHAR(50) NOT NULL,     titulo VARCHAR(150) NOT NULL,     detalle TEXT DEFAULT NULL,     user_id INT UNSIGNED DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    KEY idx_caso_historial_caso (caso_id),
    CONSTRAINT fk_caso_historial_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
