<?php require_once '../../config/app.php'; require_once '../../core/DB.php'; require_once '../../core/Auth.php';
Auth::requireLogin();
$pdo = DB::conn();
$user = Auth::user();
$denunciante = trim((string)($_POST['denunciante'] ?? ''));
$relato = trim((string)($_POST['relato'] ?? '')); $contexto = trim((string)($_POST['contexto'] ?? ''));
if ($relato === '') {     die('El relato es obligatorio.'); }
$numero = 'CASO-' . date('Ymd-His');
$stmt = $pdo->prepare("     INSERT INTO casos (         colegio_id,         numero_caso,         fecha_ingreso,         denunciante_nombre,         relato,         contexto     ) VALUES (?, ?, NOW(), ?, ?, ?)
");
$stmt->execute([
    $user['colegio_id'],
    $numero,
    $denunciante !== '' ? $denunciante : null,
    $relato,
    $contexto !== '' ? $contexto : null
]);
$casoId = (int)$pdo->lastInsertId();
$stmtHist = $pdo->prepare("     INSERT INTO caso_historial (         caso_id,         tipo_evento,         titulo,         detalle,         user_id     ) VALUES (?, ?, ?, ?, ?)
");
