CREATE TABLE IF NOT EXISTS caso_declaraciones (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     caso_id INT UNSIGNED NOT NULL,     participante_id INT UNSIGNED DEFAULT NULL,     tipo_declarante VARCHAR(20) NOT NULL,     nombre_declarante VARCHAR(150) NOT NULL,     run_declarante VARCHAR(20) DEFAULT NULL,     calidad_procesal VARCHAR(50) NOT NULL,     fecha_declaracion DATETIME NOT NULL,     texto_declaracion LONGTEXT NOT NULL,     observaciones TEXT DEFAULT NULL,     tomada_por INT UNSIGNED DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    KEY idx_caso_declaraciones_caso (caso_id),
