1. Catálogo de módulos
SQL
CREATE TABLE IF NOT EXISTS modulos_catalogo (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     codigo VARCHAR(60) NOT NULL,     nombre VARCHAR(150) NOT NULL,     descripcion TEXT DEFAULT NULL,     es_premium TINYINT(1) NOT NULL DEFAULT 0,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uq_modulos_catalogo_codigo (codigo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
2. Activación de módulos por colegio
SQL
CREATE TABLE IF NOT EXISTS colegio_modulos (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     colegio_id INT UNSIGNED NOT NULL,     modulo_codigo VARCHAR(60) NOT NULL,     activo TINYINT(1) NOT NULL DEFAULT 0,     fecha_activacion DATETIME DEFAULT NULL,     fecha_expiracion DATETIME DEFAULT NULL,     plan VARCHAR(60) DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_colegio_modulo (colegio_id, modulo_codigo),
    KEY idx_colegio_modulos_colegio (colegio_id),
    CONSTRAINT fk_colegio_modulos_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
3. Suscripciones comerciales
SQL
CREATE TABLE IF NOT EXISTS colegio_suscripciones (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     colegio_id INT UNSIGNED NOT NULL,     modulo_codigo VARCHAR(60) NOT NULL,     plan VARCHAR(60) DEFAULT NULL,     precio DECIMAL(10,2) DEFAULT NULL,     estado VARCHAR(30) NOT NULL DEFAULT 'vigente',     fecha_inicio DATE DEFAULT NULL,     fecha_fin DATE DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    KEY idx_colegio_suscripciones_colegio (colegio_id),
    CONSTRAINT fk_colegio_suscripciones_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

4. Consumo de IA
SQL
CREATE TABLE IF NOT EXISTS ia_consumo (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     colegio_id INT UNSIGNED NOT NULL,     usuario_id INT UNSIGNED DEFAULT NULL,     caso_id INT UNSIGNED DEFAULT NULL,     tipo_analisis VARCHAR(60) NOT NULL,     tokens_usados INT UNSIGNED DEFAULT 0,     costo_estimado DECIMAL(10,4) DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    KEY idx_ia_consumo_colegio (colegio_id),
    KEY idx_ia_consumo_caso (caso_id),
    CONSTRAINT fk_ia_consumo_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_ia_consumo_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE SET NULL
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
