5.7.2 — Endpoint de búsqueda dinámica
Crea modules/denuncias/buscar_persona.php
PHP
<?php require_once '../../config/app.php'; require_once '../../core/DB.php'; require_once '../../core/Auth.php'; Auth::requireLogin(); header('Content-Type: application/json; charset=utf-8');
$q = trim((string)($_GET['q'] ?? ''));
if ($q === '' || mb_strlen($q) < 2) {     echo json_encode([]);     exit; }
$pdo = DB::conn();
$resultados = [];
$like = '%' . $q . '%';
/* Ajusta nombres de columnas si tu estructura real difiere.
Aquí asumimos:
- alumnos: id, run, nombres, apellido_paterno, apellido_materno
- docentes: id, run, nombre
- apoderados: id, run, nombre
- asistentes: id, run, nombre*/
if ($pdo->query("SHOW TABLES LIKE 'alumnos'")->fetchColumn()) {
    $stmt = $pdo->prepare("         SELECT             id,             run,             CONCAT_WS(' ', nombres, apellido_paterno, apellido_materno) AS nombre
            'alumno' AS tipo
        FROM alumnos
        WHERE run LIKE ? OR nombres LIKE ? OR apellido_paterno LIKE ? OR apellido
        LIMIT 8
    ");
    $stmt->execute([$like, $like, $like, $like]);
    $resultados = array_merge($resultados, $stmt->fetchAll(PDO::FETCH_ASSOC));
}
if ($pdo->query("SHOW TABLES LIKE 'docentes'")->fetchColumn()) {
    $stmt = $pdo->prepare("         SELECT             id,             run,             nombre,             'docente' AS tipo
        FROM docentes         WHERE run LIKE ? OR nombre LIKE ?
        LIMIT 8
    ");
    $stmt->execute([$like, $like]);
    $resultados = array_merge($resultados, $stmt->fetchAll(PDO::FETCH_ASSOC));
}
if ($pdo->query("SHOW TABLES LIKE 'apoderados'")->fetchColumn()) {
    $stmt = $pdo->prepare("         SELECT             id,             run,             nombre,             'apoderado' AS tipo
        FROM apoderados         WHERE run LIKE ? OR nombre LIKE ?
        LIMIT 8
    ");
    $stmt->execute([$like, $like]);
    $resultados = array_merge($resultados, $stmt->fetchAll(PDO::FETCH_ASSOC));
}
if ($pdo->query("SHOW TABLES LIKE 'asistentes'")->fetchColumn()) {
    $stmt = $pdo->prepare("         SELECT             id,             run,             nombre,             'asistente' AS tipo
        FROM asistentes         WHERE run LIKE ? OR nombre LIKE ?
        LIMIT 8
    ");
    $stmt->execute([$like, $like]);
    $resultados = array_merge($resultados, $stmt->fetchAll(PDO::FETCH_ASSOC));
} echo json_encode(array_values($resultados));
