if (!function_exists('registrar_bitacora')) {     function registrar_bitacora(         string $modulo,         string $accion,         ?string $entidad = null,
        ?int $entidadId = null,
        ?string $descripcion = null
    ): void {
        if (!class_exists('DB') || !class_exists('Auth')) {             return;
