        ");
        $stmt->execute([
            $user['colegio_id'] ?? null,
            $user['id'] ?? null,
            $modulo,
            $accion,
            $entidad,
            $entidadId,
            $descripcion,
            $_SERVER['REMOTE_ADDR'] ?? null,             substr((string)($_SERVER['HTTP_USER_AGENT'] ?? ''), 0, 255),
        ]);
    }
}
