7.1 — SQL de seguimiento formal
Ejecuta este bloque.
A. Tabla de seguimiento del caso
SQL
CREATE TABLE IF NOT EXISTS caso_seguimiento (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     caso_id INT UNSIGNED NOT NULL,     fecha_apertura DATETIME NOT NULL,     objetivo_general TEXT DEFAULT NULL,     estado VARCHAR(30) NOT NULL DEFAULT 'activo',     responsable_general_id INT UNSIGNED DEFAULT NULL,     fecha_cierre DATETIME DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    UNIQUE KEY uq_caso_seguimiento_caso (caso_id),
    KEY idx_caso_seguimiento_caso (caso_id),
    CONSTRAINT fk_caso_seguimiento_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

B. Plan de intervención
SQL
CREATE TABLE IF NOT EXISTS caso_plan_intervencion (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     seguimiento_id INT UNSIGNED NOT NULL,
    titulo VARCHAR(150) NOT NULL,     descripcion TEXT DEFAULT NULL,     responsable_id INT UNSIGNED DEFAULT NULL,     fecha_inicio DATE DEFAULT NULL,     fecha_vencimiento DATE DEFAULT NULL,     estado VARCHAR(30) NOT NULL DEFAULT 'pendiente',     prioridad VARCHAR(20) NOT NULL DEFAULT 'media',     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA
    PRIMARY KEY (id),
    KEY idx_caso_plan_intervencion_seg (seguimiento_id),
    CONSTRAINT fk_caso_plan_intervencion_seg
        FOREIGN KEY (seguimiento_id) REFERENCES caso_seguimiento(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
C. Avances del plan
SQL
CREATE TABLE IF NOT EXISTS caso_seguimiento_avances (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     plan_id INT UNSIGNED NOT NULL,     descripcion TEXT NOT NULL,     porcentaje_avance INT UNSIGNED NOT NULL DEFAULT 0,     registrado_por INT UNSIGNED DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    KEY idx_caso_seguimiento_avances_plan (plan_id),
    CONSTRAINT fk_caso_seguimiento_avances_plan
        FOREIGN KEY (plan_id) REFERENCES caso_plan_intervencion(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
D. Alertas automáticas de seguimiento
SQL
CREATE TABLE IF NOT EXISTS caso_alertas (     id INT UNSIGNED NOT NULL AUTO_INCREMENT,     caso_id INT UNSIGNED NOT NULL,     seguimiento_id INT UNSIGNED DEFAULT NULL,     plan_id INT UNSIGNED DEFAULT NULL,     tipo VARCHAR(50) NOT NULL,     mensaje TEXT NOT NULL,     prioridad VARCHAR(20) NOT NULL DEFAULT 'media',     estado VARCHAR(20) NOT NULL DEFAULT 'pendiente',     fecha_alerta DATETIME NOT NULL,     atendida_por INT UNSIGNED DEFAULT NULL,     fecha_atendida DATETIME DEFAULT NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    KEY idx_caso_alertas_caso (caso_id),
    KEY idx_caso_alertas_seg (seguimiento_id),
    KEY idx_caso_alertas_plan (plan_id),
    CONSTRAINT fk_caso_alertas_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_caso_alertas_seg
        FOREIGN KEY (seguimiento_id) REFERENCES caso_seguimiento(id)
        ON DELETE SET NULL
        ON UPDATE CASCADE,
    CONSTRAINT fk_caso_alertas_plan
        FOREIGN KEY (plan_id) REFERENCES caso_plan_intervencion(id)
        ON DELETE SET NULL
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
