<?php declare(strict_types=1);
final class CSRF {     private const KEY = '_csrf_token';
    public static function start(): void
    {         if (session_status() !== PHP_SESSION_ACTIVE) {             session_start();
        }         if (empty($_SESSION[self::KEY])) {             self::regenerate();         }     }
    public static function regenerate(): void
    {
        $_SESSION[self::KEY] = bin2hex(random_bytes(32));
    }     public static function token(): string     {         self::start();         return (string)$_SESSION[self::KEY];
    }
    public static function field(): string
    {         return '<input type="hidden" name="_token" value="' . htmlspecialchars(se
    }
    public static function validate(?string $token): bool
    {         self::start();         return is_string($token) && hash_equals((string)$_SESSION[self::KEY], $to
    }
}
B. Uso en formularios (todos)Agregar dentro de <form> :
PHP
<?= CSRF::field(); ?>
