Al inicio de cada guardar_*.php , actualizar_*.php , etc.:
    PHP require_once '../../core/CSRF.php'; if (!CSRF::validate($_POST['_token'] ?? null)) {     http_response_code(403);     exit('Token CSRF inválido.'); }
9.2 — Permisos por rol (RBAC básico)
A. Helper en core/helpers.php
PHP
if (!function_exists('tiene_permiso')) {     function tiene_permiso(string $codigo): bool     {         if (!class_exists('DB') || !class_exists('Auth')) {             return false;         }
        $pdo = DB::conn();
        $user = Auth::user();
        $stmt = $pdo->prepare("
            SELECT 1
            FROM rol_permisos rp
            INNER JOIN permisos p ON p.id = rp.permiso_id             WHERE rp.rol_id = ?
              AND p.codigo = ?
            LIMIT 1
        ");         $stmt->execute([$user['rol_id'], $codigo]);         return (bool)$stmt->fetchColumn();
    }
}
