<?php require_once '../../config/app.php'; require_once '../../core/DB.php'; require_once '../../core/Auth.php'; use Dompdf\Dompdf;
Auth::requireLogin();
$pdo = DB::conn();
$user = Auth::user();
$casoId = (int)($_GET['id'] ?? 0);
$modo = $_GET['modo'] ?? 'interno';
/* =========================
   DATOS CASO
========================= */
$stmt = $pdo->prepare("
    SELECT c.*, col.nombre AS colegio_nombre, col.logo_url, col.director_nombre
    FROM casos c
    INNER JOIN colegios col ON col.id = c.colegio_id
    WHERE c.id = ? AND c.colegio_id = ?
");
$stmt->execute([$casoId, $user['colegio_id']]);
$caso = $stmt->fetch(); if (!$caso) die('Caso no encontrado');
/* =========================
   PARTICIPANTES
========================= */
$stmt = $pdo->prepare("
    SELECT *
    FROM caso_participantes     WHERE caso_id = ?
");
$stmt->execute([$casoId]);
$participantes = $stmt->fetchAll();
/* =========================
   DECLARACIONES
========================= */
$stmt = $pdo->prepare("
    SELECT *
    FROM caso_declaraciones     WHERE caso_id = ?
");
$stmt->execute([$casoId]);
$declaraciones = $stmt->fetchAll();
/* =========================
   FOLIO Y VALIDACIÓN
========================= */
$folio = 'METIS-' . date('Ymd') . '-' . str_pad($casoId, 6, '0', STR_PAD_LEFT);
$hash = substr(hash('sha256', $folio . $caso['numero_caso']), 0, 12);
/* =========================
   FUNCIONES PRIVACIDAD ========================= */
function nombreSeguro($p, $modo) {     if ($p['rol_en_caso'] === 'denunciante' && !empty($p['solicita_reserva_identi         return $modo === 'interno'
            ? 'Denunciante con identidad reservada'
            : $p['nombre_referencial'];
    }     return $p['nombre_referencial'];
}
/* =========================
   HTML PROFESIONAL
========================= */
$html = ' <style> body { font-family: Arial; font-size: 12px; } .header { display:flex; justify-content:space-between; }
.logo { height:60px; }
.title { text-align:center; margin-top:20px; }
