        <img src="' . $caso['logo_url'] . '" class="logo">
    </div>
</div>
<div class="title">
    <h2>INFORME DE CONVIVENCIA ESCOLAR</h2>
    <strong>Folio: ' . $folio . '</strong><br>
    Código validación: ' . $hash . '
</div>
<div class="section">
<strong>Caso:</strong> ' . $caso['numero_caso'] . '<br>
<strong>Fecha:</strong> ' . $caso['fecha_ingreso'] . '<br>
<strong>Estado:</strong> ' . $caso['estado'] . '<br>
</div>
<div class="section">
<h3>1. Relato</h3>
' . nl2br(htmlspecialchars($caso['relato'])) . '
</div>
<div class="section">
<h3>2. Intervinientes</h3>
<table class="table">
<tr><th>Rol</th><th>Nombre</th><th>RUN</th></tr>';
foreach ($participantes as $p) {     $html .= '<tr>
        <td>'.$p['rol_en_caso'].'</td>
        <td>'.nombreSeguro($p,$modo).'</td>
        <td>'.$p['run'].'</td>
    </tr>';
}
$html .= '</table></div>';
$html .= '<div class="section"><h3>3. Declaraciones</h3>'; foreach ($declaraciones as $d) {
    $html .= '<p><strong>'.$d['nombre_declarante'].'</strong>:<br>'
