<script> document.querySelectorAll('.busqueda-persona').forEach(input => {     input.addEventListener('keyup', async () => {         const q = input.value.trim();         const id = input.dataset.target;         const box = document.getElementById('resultados-' + id);
        if (q.length < 2) {             box.innerHTML = '';             return;         }
        const res = await fetch('buscar_persona.php?q=' + encodeURIComponent(q));         const data = await res.json();         box.innerHTML = '';
        data.forEach(p => {             const div = document.createElement('div');             div.style.padding = '8px';             div.style.cursor = 'pointer';             div.style.borderBottom = '1px solid #e2e8f0';             div.textContent = `${p.nombre} (${p.tipo}) - ${p.run ?? ''}`;
            div.onclick = () => {                 document.getElementById('persona_id_' + id).value = p.id;                 document.getElementById('tipo_persona_' + id).value = p.tipo;                 document.getElementById('nombre_ref_' + id).value = p.nombre;                 document.getElementById('run_' + id).value = p.run ?? '';                 box.innerHTML = '';
            };
            box.appendChild(div);
        });
    });
});
</script>
