<?php declare(strict_types=1);
require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php'; require_once dirname(__DIR__, 2) . '/core/helpers.php'; require_once dirname(__DIR__, 2) . '/core/CSRF.php';
Auth::requireLogin();
$pdo = DB::conn();
$user = Auth::user();
$colegioId = (int)($user['colegio_id'] ?? 0);
$casoId = (int)($_GET['caso_id'] ?? 0); if ($casoId <= 0) {     die('Debe indicar un caso.'); }
$stmt = $pdo->prepare("
    SELECT c.*, ec.nombre AS estado_formal
    FROM casos c
    LEFT JOIN estado_caso ec ON ec.id = c.estado_caso_id     WHERE c.id = ? AND c.colegio_id = ?
    LIMIT 1
");
$stmt->execute([$casoId, $colegioId]); $caso = $stmt->fetch(PDO::FETCH_ASSOC);
if (!$caso) {     die('Caso no encontrado.'); }
$stmt = $pdo->prepare("
    SELECT *
    FROM caso_seguimiento     WHERE caso_id = ?
    LIMIT 1
");
$stmt->execute([$casoId]);
$seguimiento = $stmt->fetch(PDO::FETCH_ASSOC);
$planes = [];
$alertas = []; $avancesPorPlan = [];
if ($seguimiento) {
    $stmt = $pdo->prepare("
        SELECT *
        FROM caso_plan_intervencion         WHERE seguimiento_id = ?
        ORDER BY id DESC
    ");
    $stmt->execute([(int)$seguimiento['id']]);
    $planes = $stmt->fetchAll(PDO::FETCH_ASSOC);
    $stmt = $pdo->prepare("
        SELECT *
        FROM caso_alertas         WHERE seguimiento_id = ?
        ORDER BY id DESC
    ");
    $stmt->execute([(int)$seguimiento['id']]);     $alertas = $stmt->fetchAll(PDO::FETCH_ASSOC);
    if ($planes) {
        $ids = array_map(fn($p) => (int)$p['id'], $planes);
        $placeholders = implode(',', array_fill(0, count($ids), '?'));
        $stmt = $pdo->prepare("
            SELECT *
            FROM caso_seguimiento_avances
            WHERE plan_id IN ($placeholders)
            ORDER BY id DESC
        ");
        $stmt->execute($ids);
        $avances = $stmt->fetchAll(PDO::FETCH_ASSOC);
        foreach ($avances as $a) {
            $avancesPorPlan[(int)$a['plan_id']][] = $a;
        }
    }
}
