                if (personaId) personaId.value = p.id;                 if (tipoPersona) tipoPersona.value = p.tipo;                 if (nombreRef) nombreRef.value = p.nombre;                 if (run) run.value = p.run ?? '';
                box.innerHTML = '';
            };
            box.appendChild(div);
        });
    });
});
</script>
