SET FOREIGN_KEY_CHECKS = 0;
-- =========================
-- ALUMNOS
-- ========================= CREATE TABLE IF NOT EXISTS alumnos (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     run VARCHAR(12) NOT NULL,     nombres VARCHAR(100) NOT NULL,     apellido_paterno VARCHAR(80) NOT NULL,     apellido_materno VARCHAR(80) NULL,     fecha_nacimiento DATE NULL,     curso VARCHAR(50) NULL,     activo TINYINT(1) DEFAULT 1,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE KEY uq_alumno_run_colegio (run, colegio_id),
    INDEX idx_alumnos_colegio (colegio_id),
    INDEX idx_alumnos_nombre (nombres, apellido_paterno),
    CONSTRAINT fk_alumnos_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
-- =========================
-- APODERADOS
-- ========================= CREATE TABLE IF NOT EXISTS apoderados (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     run VARCHAR(12) NOT NULL,     nombre VARCHAR(150) NOT NULL,     telefono VARCHAR(30) NULL,     email VARCHAR(120) NULL,     activo TINYINT(1) DEFAULT 1,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE KEY uq_apoderado_run_colegio (run, colegio_id),     INDEX idx_apoderados_colegio (colegio_id),
    INDEX idx_apoderados_nombre (nombre),
    CONSTRAINT fk_apoderados_colegio
        FOREIGN KEY (colegio_id) REFERENCES colegios(id)
        ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
-- =========================
-- RELACIÓN ALUMNO-APODERADO
-- =========================
CREATE TABLE IF NOT EXISTS alumno_apoderado (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     alumno_id INT UNSIGNED NOT NULL,     apoderado_id INT UNSIGNED NOT NULL,     es_titular TINYINT(1) DEFAULT 0,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE KEY uq_relacion (alumno_id, apoderado_id),
    CONSTRAINT fk_rel_alumno
        FOREIGN KEY (alumno_id) REFERENCES alumnos(id)
        ON DELETE CASCADE,
    CONSTRAINT fk_rel_apoderado
        FOREIGN KEY (apoderado_id) REFERENCES apoderados(id)
        ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
SET FOREIGN_KEY_CHECKS = 1;
