11.6.1 — Parche SQL para baja lógica
Ejecuta este bloque:
SQL
ALTER TABLE alumnos
ADD COLUMN fecha_baja DATETIME NULL AFTER activo,
ADD COLUMN motivo_baja VARCHAR(255) NULL AFTER fecha_baja;
ALTER TABLE apoderados
ADD COLUMN fecha_baja DATETIME NULL AFTER activo,
ADD COLUMN motivo_baja VARCHAR(255) NULL AFTER fecha_baja;
ALTER TABLE docentes
ADD COLUMN fecha_baja DATETIME NULL AFTER activo,
ADD COLUMN motivo_baja VARCHAR(255) NULL AFTER fecha_baja;
ALTER TABLE asistentes
ADD COLUMN fecha_baja DATETIME NULL AFTER activo,
ADD COLUMN motivo_baja VARCHAR(255) NULL AFTER fecha_baja;
Validación
SQL
DESCRIBE alumnos;
DESCRIBE apoderados;
DESCRIBE docentes;
DESCRIBE asistentes;
Debes ver: activo fecha_baja  motivo_baja
11.6.2 — Endpoint único para baja / reactivación
Crea modules/comunidad/cambiar_estado.php
PHP
<?php declare(strict_types=1);
require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php'; require_once dirname(__DIR__, 2) . '/core/helpers.php'; require_once dirname(__DIR__, 2) . '/core/CSRF.php'; Auth::requireLogin();
if (!CSRF::validate($_POST['_token'] ?? null)) {     exit('CSRF inválido'); }
$pdo = DB::conn();
$user = Auth::user();
$colegioId = (int)$user['colegio_id'];
$tabla = clean($_POST['tabla'] ?? '');
$id = cleanInt($_POST['id'] ?? 0);
$accion = clean($_POST['accion'] ?? '');
$motivo = clean($_POST['motivo_baja'] ?? '');
$tab = clean($_POST['tab'] ?? 'alumnos');
$tablasPermitidas = ['alumnos', 'apoderados', 'docentes', 'asistentes']; if (!in_array($tabla, $tablasPermitidas, true)) {     exit('Tabla no permitida.');
}
if ($id <= 0 || !in_array($accion, ['baja', 'reactivar'], true)) {     exit('Datos inválidos.'); }
$stmt = $pdo->prepare("
    SELECT id
    FROM {$tabla}
    WHERE id = ? AND colegio_id = ?
    LIMIT 1
");
$stmt->execute([$id, $colegioId]); $fila = $stmt->fetch(PDO::FETCH_ASSOC);
if (!$fila) {     exit('Registro no encontrado.');
}
if ($accion === 'baja') {     $stmt = $pdo->prepare("
        UPDATE {$tabla}         SET activo = 0,             fecha_baja = NOW(),             motivo_baja = ?         WHERE id = ?     ");
    $stmt->execute([
        $motivo !== '' ? $motivo : null,
        $id
    ]);
} else {
    $stmt = $pdo->prepare("
        UPDATE {$tabla}
        SET activo = 1,             fecha_baja = NULL,             motivo_baja = NULL         WHERE id = ?
    ");
    $stmt->execute([$id]);
}
header('Location: ' . APP_URL . '/modules/comunidad/index.php?tab=' . urlencode($ exit;
