?? 13.1 — SQL base
Ejecuta este bloque completo:
SQL
SET FOREIGN_KEY_CHECKS = 0;
-- =========================
-- REGLAMENTOS
-- ========================= CREATE TABLE reglamentos (     id INT AUTO_INCREMENT PRIMARY KEY,     colegio_id INT NOT NULL,     nombre VARCHAR(150) NOT NULL,     descripcion TEXT,     vigente TINYINT(1) DEFAULT 1,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX (colegio_id)
) ENGINE=InnoDB;
-- =========================
-- ARTÍCULOS
-- ========================= CREATE TABLE reglamento_articulos (     id INT AUTO_INCREMENT PRIMARY KEY,     reglamento_id INT NOT NULL,     codigo VARCHAR(50),     titulo VARCHAR(150),     contenido TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX (reglamento_id),
    FOREIGN KEY (reglamento_id) REFERENCES reglamentos(id) ON DELETE CASCADE
) ENGINE=InnoDB;
-- =========================
-- FALTAS
-- ========================= CREATE TABLE faltas (     id INT AUTO_INCREMENT PRIMARY KEY,     reglamento_id INT NOT NULL,     articulo_id INT NULL,     nombre VARCHAR(150) NOT NULL,     descripcion TEXT,
    gravedad ENUM('leve','media','grave') DEFAULT 'media',     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX (reglamento_id),
    FOREIGN KEY (reglamento_id) REFERENCES reglamentos(id) ON DELETE CASCADE,
    FOREIGN KEY (articulo_id) REFERENCES reglamento_articulos(id) ON DELETE SET N
) ENGINE=InnoDB;
-- =========================
-- MEDIDAS
-- ========================= CREATE TABLE medidas (     id INT AUTO_INCREMENT PRIMARY KEY,     reglamento_id INT NOT NULL,     tipo ENUM('formativa','disciplinaria') NOT NULL,     nombre VARCHAR(150) NOT NULL,     descripcion TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX (reglamento_id),
    FOREIGN KEY (reglamento_id) REFERENCES reglamentos(id) ON DELETE CASCADE
) ENGINE=InnoDB;
-- =========================
-- RELACIÓN FALTA - MEDIDA
-- ========================= CREATE TABLE falta_medida (     id INT AUTO_INCREMENT PRIMARY KEY,     falta_id INT NOT NULL,     medida_id INT NOT NULL,
    UNIQUE KEY (falta_id, medida_id),
    FOREIGN KEY (falta_id) REFERENCES faltas(id) ON DELETE CASCADE,
    FOREIGN KEY (medida_id) REFERENCES medidas(id) ON DELETE CASCADE
) ENGINE=InnoDB;
SET FOREIGN_KEY_CHECKS = 1;
