<?php declare(strict_types=1);
require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php';
Auth::requireLogin();
$pdo = DB::conn();
$user = Auth::user();
$colegioId = (int)$user['colegio_id'];
$fechaDesde = trim((string)($_GET['fecha_desde'] ?? ''));
$fechaHasta = trim((string)($_GET['fecha_hasta'] ?? ''));
$curso = trim((string)($_GET['curso'] ?? ''));
$estado = trim((string)($_GET['estado'] ?? ''));
$semaforo = trim((string)($_GET['semaforo'] ?? ''));
$prioridad = trim((string)($_GET['prioridad'] ?? ''));
$sql = "     SELECT
        c.numero_caso,
        c.fecha_ingreso,
        a.curso,
        ec.nombre AS estado_formal,
        c.semaforo,
        c.prioridad,
        f.nombre AS falta_nombre,
        c.relato     FROM casos c
    LEFT JOIN estado_caso ec ON ec.id = c.estado_caso_id
    LEFT JOIN faltas f ON f.id = c.falta_id
    LEFT JOIN caso_participantes cp 
        ON cp.caso_id = c.id 
       AND cp.tipo_persona = 'alumno'
    LEFT JOIN alumnos a 
        ON a.id = cp.persona_id     WHERE c.colegio_id = ?
";
$params = [$colegioId];
if ($fechaDesde !== '') {
    $sql .= " AND DATE(c.fecha_ingreso) >= ? ";
    $params[] = $fechaDesde;
} if ($fechaHasta !== '') {
    $sql .= " AND DATE(c.fecha_ingreso) <= ? ";
    $params[] = $fechaHasta;
} if ($curso !== '') {
    $sql .= " AND a.curso = ? ";
    $params[] = $curso;
} if ($estado !== '') {
    $sql .= " AND ec.nombre = ? ";
    $params[] = $estado;
} if ($semaforo !== '') {
    $sql .= " AND c.semaforo = ? ";
    $params[] = $semaforo;
}
if ($prioridad !== '') {
    $sql .= " AND c.prioridad = ? ";
    $params[] = $prioridad;
}
$sql .= " ORDER BY c.id DESC ";
$stmt = $pdo->prepare($sql);
$stmt->execute($params);
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
header('Content-Type: text/csv; charset=utf-8'); header('Content-Disposition: attachment; filename=reporte_metis.csv');
$output = fopen('php://output', 'w');
fputcsv($output, [     'Numero Caso',
    'Fecha Ingreso',     'Curso',
    'Estado Formal',
    'Semaforo',
    'Prioridad',
    'Falta',     'Relato' ], ';');
foreach ($rows as $r) {     fputcsv($output, [         $r['numero_caso'] ?? '',
        $r['fecha_ingreso'] ?? '',         $r['curso'] ?? '',
        $r['estado_formal'] ?? '',
        $r['semaforo'] ?? '',
        $r['prioridad'] ?? '',
        $r['falta_nombre'] ?? '',
        $r['relato'] ?? ''
    ], ';'); }
fclose($output); exit;
