?? 17.2 — Servicio IA
?? Crear: core/IAService.php
PHP
<?php declare(strict_types=1);
final class IAService
{     public static function analizarCaso(array $data): ?string
    {
        $apiKey = getenv('ANTHROPIC_API_KEY');
        if (!$apiKey) {             return 'API Key no configurada.';         }
        $prompt = self::buildPrompt($data);
        $payload = [
            "model" => "claude-3-sonnet-20240229",
            "max_tokens" => 1000,
            "messages" => [
                [
                    "role" => "user",
                    "content" => $prompt
                ]
            ]
        ];
        $ch = curl_init("https://api.anthropic.com/v1/messages");         curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => json_encode($payload),
            CURLOPT_HTTPHEADER => [
                "Content-Type: application/json",
                "x-api-key: $apiKey",
                "anthropic-version: 2023-06-01"
            ]
        ]);
        $response = curl_exec($ch);
        if (!$response) {             return 'Error en conexión IA.';         }
        $result = json_decode($response, true);
        return $result['content'][0]['text'] ?? 'Sin respuesta IA.';
    }
    private static function buildPrompt(array $d): string
    {         return "
Eres un experto en convivencia escolar y normativa educacional.
Analiza el siguiente caso:
Relato:
{$d['relato']}
Participantes:
{$d['participantes']}
Declaraciones:
{$d['declaraciones']}
Falta asociada:
{$d['falta']}
Medidas posibles:
{$d['medidas']}
Responde estructurado en:
1. Clasificación del hecho
2. Nivel de gravedad3. Riesgos identificados
4. Medidas sugeridas
5. Observaciones profesionales
";
    }
}
