?? modules/denuncias/analizar_ia.php
PHP
<?php require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php'; require_once dirname(__DIR__, 2) . '/core/IAService.php';
Auth::requireLogin();
$pdo = DB::conn();
$casoId = (int)($_GET['id'] ?? 0);
$caso = $pdo->query("SELECT * FROM casos WHERE id = $casoId")->fetch(); if (!$caso) exit('Caso no encontrado');
$participantes = $pdo->query("
SELECT nombre_ref FROM caso_participantes WHERE caso_id = $casoId
")->fetchAll(PDO::FETCH_COLUMN);
$declaraciones = $pdo->query("
SELECT contenido FROM caso_declaraciones WHERE caso_id = $casoId
")->fetchAll(PDO::FETCH_COLUMN);
$falta = $pdo->query("
SELECT nombre FROM faltas WHERE id = {$caso['falta_id']}
")->fetchColumn();
$medidas = $pdo->query("
SELECT m.nombre
FROM falta_medida fm
JOIN medidas m ON m.id = fm.medida_id
WHERE fm.falta_id = {$caso['falta_id']}
")->fetchAll(PDO::FETCH_COLUMN);
$data = [
    'relato' => $caso['relato'],
    'participantes' => implode(', ', $participantes),     'declaraciones' => implode("\n", $declaraciones),
    'falta' => $falta,
    'medidas' => implode(', ', $medidas)
];
$resultado = IAService::analizarCaso($data);
$stmt = $pdo->prepare("
INSERT INTO caso_analisis_ia (caso_id, resultado)
VALUES (?, ?)
");
$stmt->execute([$casoId, $resultado]); header("Location: ver.php?id=$casoId&tab=analisis");
