CREATE TABLE colegio_modulos (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     modulo_codigo VARCHAR(60) NOT NULL,     activo TINYINT(1) NOT NULL DEFAULT 0,     fecha_activacion DATETIME NULL,     fecha_expiracion DATETIME NULL,     plan VARCHAR(60) NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA     UNIQUE KEY uq_colegio_modulo (colegio_id, modulo_codigo),
    CONSTRAINT fk_colegio_modulos_colegio FOREIGN KEY (colegio_id) REFERENCES col
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE colegio_suscripciones (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     modulo_codigo VARCHAR(60) NOT NULL,     plan VARCHAR(60) NULL,     precio DECIMAL(10,2) NULL,     estado VARCHAR(30) NOT NULL DEFAULT 'vigente',     fecha_inicio DATE NULL,     fecha_fin DATE NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTA     CONSTRAINT fk_suscripciones_colegio FOREIGN KEY (colegio_id) REFERENCES coleg
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE ia_consumo (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     usuario_id INT UNSIGNED NULL,     caso_id INT UNSIGNED NULL,     tipo_analisis VARCHAR(60) NOT NULL,     tokens_usados INT UNSIGNED DEFAULT 0,     costo_estimado DECIMAL(10,4) NULL,     created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    KEY idx_ia_consumo_caso (caso_id),
    CONSTRAINT fk_ia_colegio FOREIGN KEY (colegio_id) REFERENCES colegios(id) ON 
    CONSTRAINT fk_ia_usuario FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON     CONSTRAINT fk_ia_caso FOREIGN KEY (caso_id) REFERENCES casos(id) ON DELETE SE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE caso_analisis_ia (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     caso_id INT UNSIGNED NOT NULL,     resultado LONGTEXT NULL,
    created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    KEY idx_analisis_caso (caso_id),
    CONSTRAINT fk_analisis_caso FOREIGN KEY (caso_id) REFERENCES casos(id) ON DEL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
-- =========================================================
-- LOGS
-- ========================================================= CREATE TABLE logs_sistema (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NULL,     usuario_id INT UNSIGNED NULL,     modulo VARCHAR(100) NOT NULL,     accion VARCHAR(100) NOT NULL,     entidad VARCHAR(100) NULL,     entidad_id INT UNSIGNED NULL,     descripcion TEXT NULL,     ip VARCHAR(50) NULL,     user_agent VARCHAR(255) NULL,
    created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    KEY idx_logs_colegio (colegio_id),
    KEY idx_logs_usuario (usuario_id),
    CONSTRAINT fk_logs_colegio FOREIGN KEY (colegio_id) REFERENCES colegios(id) O
    CONSTRAINT fk_logs_usuario FOREIGN KEY (usuario_id) REFERENCES usuarios(id) O ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
