<script> const UF = 40040; function calcular() {
    let alumnos = parseInt(document.getElementById('alumnos').value) || 0;     let usuarios = parseInt(document.getElementById('usuarios').value) || 0;     let ia = document.getElementById('ia').checked;     let base = 0;
    if (alumnos <= 300) base = 49000;     else if (alumnos <= 800) base = 79000;     else if (alumnos <= 1500) base = 119000;     else base = 159000;     let iaCosto = 0;
    if (ia) {         if (alumnos <= 300) iaCosto = 40000;         else if (alumnos <= 800) iaCosto = 50000;         else if (alumnos <= 1500) iaCosto = 60000;         else iaCosto = 80000;
    }     let usuariosCosto = usuarios * 3000;
    let total = base + iaCosto + usuariosCosto;     let uf = (total / UF).toFixed(2);     let plan = "Base";
    if (ia && alumnos > 800) plan = "Institucional";     else if (ia) plan = "Profesional";
    document.getElementById('resultado').innerHTML = `
        <div class="card-sgce p-4 mt-3">
            <h3>Resultado</h3>
            <p><strong>Plan:</strong> ${plan}</p>
            <p><strong>Valor mensual:</strong> $${total.toLocaleString()}</p>             <p><strong>Equivalente UF:</strong> ${uf} UF</p>
            <hr>
            <p><strong>Detalle:</strong></p>
            <ul>
                <li>Base: $${base.toLocaleString()}</li>
                <li>IA: $${iaCosto.toLocaleString()}</li>
                <li>Usuarios: $${usuariosCosto.toLocaleString()}</li>
            </ul>
        </div>
    `; }
document.querySelectorAll('#alumnos, #usuarios, #ia')     .forEach(e => e.addEventListener('input', calcular));
calcular(); </script>
