CREATE TABLE denuncia_areas (     id INT UNSIGNED PRIMARY KEY,     nombre VARCHAR(180) NOT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1 ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4; CREATE TABLE denuncia_aspectos (     id INT UNSIGNED PRIMARY KEY,     area_id INT UNSIGNED NOT NULL,     nombre VARCHAR(255) NOT NULL,     activo TINYINT(1) NOT NULL DEFAULT 1,
    CONSTRAINT fk_aspecto_area
        FOREIGN KEY (area_id) REFERENCES denuncia_areas(id)
        ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE casos
ADD COLUMN denuncia_aspecto_id INT UNSIGNED NULL AFTER falta_id,
ADD CONSTRAINT fk_casos_denuncia_aspecto
    FOREIGN KEY (denuncia_aspecto_id) REFERENCES denuncia_aspectos(id)
    ON DELETE SET NULL;
CREATE TABLE aula_segura_procedimientos (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     caso_id INT UNSIGNED NOT NULL,     aplica TINYINT(1) NOT NULL DEFAULT 0,     causal VARCHAR(255) NULL,     medida_cautelar_suspension TINYINT(1) NOT NULL DEFAULT 0,     fecha_notificacion_suspension DATE NULL,     fecha_limite_resolucion DATE NULL,     fecha_notificacion_resolucion DATE NULL,     fecha_limite_reconsideracion DATE NULL,     reconsideracion_presentada TINYINT(1) NOT NULL DEFAULT 0,     fecha_reconsideracion DATE NULL,     estado VARCHAR(50) NOT NULL DEFAULT 'no_aplica',     observaciones TEXT NULL,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY uq_aula_segura_caso (caso_id),
    CONSTRAINT fk_aula_segura_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
