20.1 — SQL base
Ejecuta en phpMyAdmin:
SQL
CREATE TABLE IF NOT EXISTS medidas_catalogo (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     tipo ENUM('formativa','psicosocial','reparatoria','disciplinaria') NOT NULL,     nombre VARCHAR(180) NOT NULL,     descripcion TEXT NULL,     aplica_estudiante TINYINT(1) NOT NULL DEFAULT 1,     aplica_apoderado TINYINT(1) NOT NULL DEFAULT 0,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_medidas_catalogo_colegio (colegio_id),
    INDEX idx_medidas_catalogo_tipo (tipo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS falta_medidas_catalogo (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     falta_id INT UNSIGNED NOT NULL,     medida_id INT UNSIGNED NOT NULL,     obligatoria TINYINT(1) NOT NULL DEFAULT 0,     orden INT UNSIGNED NOT NULL DEFAULT 0,
    UNIQUE KEY uq_falta_medida_catalogo (falta_id, medida_id),
    INDEX idx_fmc_falta (falta_id),
    INDEX idx_fmc_medida (medida_id),
    CONSTRAINT fk_fmc_falta
        FOREIGN KEY (falta_id) REFERENCES faltas(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_fmc_medida         FOREIGN KEY (medida_id) REFERENCES medidas_catalogo(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS caso_medidas (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     caso_id INT UNSIGNED NOT NULL,     medida_id INT UNSIGNED NOT NULL,     tipo ENUM('formativa','psicosocial','reparatoria','disciplinaria') NOT NULL,     fundamento TEXT NULL,     fecha_aplicacion DATE NULL,     responsable VARCHAR(150) NULL,     estado ENUM('propuesta','aplicada','en_seguimiento','cerrada','revocada') NOT     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_cm_caso (caso_id),
    INDEX idx_cm_medida (medida_id),
    CONSTRAINT fk_cm_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_cm_medida
        FOREIGN KEY (medida_id) REFERENCES medidas_catalogo(id)
        ON DELETE RESTRICT
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS caso_debido_proceso (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     caso_id INT UNSIGNED NOT NULL,     notificacion_inicio TINYINT(1) NOT NULL DEFAULT 0,     fecha_notificacion_inicio DATE NULL,     derecho_descargos TINYINT(1) NOT NULL DEFAULT 0,     fecha_descargos DATE NULL,     se_escucho_estudiante TINYINT(1) NOT NULL DEFAULT 0,     se_informo_apoderado TINYINT(1) NOT NULL DEFAULT 0,     decision_fundada TINYINT(1) NOT NULL DEFAULT 0,     fecha_decision DATE NULL,     derecho_reconsideracion TINYINT(1) NOT NULL DEFAULT 0,     fecha_reconsideracion DATE NULL,     observaciones TEXT NULL,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY uq_debido_proceso_caso (caso_id),
    CONSTRAINT fk_cdp_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
