PHP
<?php
declare(strict_types=1); require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php'; require_once dirname(__DIR__, 2) . '/core/helpers.php'; require_once dirname(__DIR__, 2) . '/core/CSRF.php'; Auth::requireLogin();
if (!CSRF::validate($_POST['_token'] ?? null)) {     exit('CSRF inválido.'); }
$pdo = DB::conn();
$user = Auth::user();
$colegioId = (int)($user['colegio_id'] ?? 0);
$userId = (int)($user['id'] ?? 0);
$casoId = cleanInt($_POST['caso_id'] ?? 0);
$medidaId = cleanInt($_POST['medida_id'] ?? 0);
$tipo = clean($_POST['tipo'] ?? 'formativa');
$fechaAplicacion = clean($_POST['fecha_aplicacion'] ?? '');
$responsable = clean($_POST['responsable'] ?? '');
$estado = clean($_POST['estado'] ?? 'propuesta');
$fundamento = cleanText($_POST['fundamento'] ?? '');
$tiposPermitidos = ['formativa','psicosocial','reparatoria','disciplinaria']; $estadosPermitidos = ['propuesta','aplicada','en_seguimiento','cerrada','revocada
if ($casoId <= 0 || $medidaId <= 0) {     exit('Datos incompletos.');
}
if (!in_array($tipo, $tiposPermitidos, true)) {     $tipo = 'formativa';
} if (!in_array($estado, $estadosPermitidos, true)) {     $estado = 'propuesta';
}
$stmt = $pdo->prepare("
    SELECT id
    FROM casos     WHERE id = ?
      AND colegio_id = ?
    LIMIT 1
");
$stmt->execute([$casoId, $colegioId]);
if (!$stmt->fetchColumn()) {     exit('Caso no encontrado.'); }
$stmt = $pdo->prepare("
    SELECT id, tipo
    FROM medidas_catalogo     WHERE id = ?
      AND colegio_id = ?
      AND activo = 1
    LIMIT 1
");
$stmt->execute([$medidaId, $colegioId]); $medida = $stmt->fetch(PDO::FETCH_ASSOC);
if (!$medida) {     exit('Medida inválida.'); }
$tipo = (string)$medida['tipo'];
$stmt = $pdo->prepare("     INSERT INTO caso_medidas (         caso_id,         medida_id,
        tipo,         fundamento,         fecha_aplicacion,         responsable,         estado     ) VALUES (?, ?, ?, ?, ?, ?, ?)
");
$stmt->execute([
    $casoId,
    $medidaId,
    $tipo,
    $fundamento !== '' ? $fundamento : null,
    $fechaAplicacion !== '' ? $fechaAplicacion : null,
    $responsable !== '' ? $responsable : null,
    $estado,
]);
$stmt = $pdo->prepare("     INSERT INTO caso_historial (         caso_id,         tipo_evento,         titulo,         detalle,         user_id     ) VALUES (?, ?, ?, ?, ?)
");
$stmt->execute([
    $casoId,
    'medida',
    'Medida registrada',
    'Se registra una medida de tipo ' . $tipo . '.',
    $userId > 0 ? $userId : null,
]);
header('Location: ' . APP_URL . '/modules/denuncias/ver.php?id=' . $casoId); exit;
