<?php declare(strict_types=1);
require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php'; require_once dirname(__DIR__, 2) . '/core/helpers.php'; require_once dirname(__DIR__, 2) . '/core/CSRF.php'; Auth::requireLogin();
