if (!$stmt->fetchColumn()) {     exit('Caso no encontrado.'); }
$boolFields = [
    'notificacion_inicio',
    'derecho_descargos',
    'se_escucho_estudiante',
    'se_informo_apoderado',
    'decision_fundada',
