$fechaDescargos = clean($_POST['fecha_descargos'] ?? '');
$fechaDecision = clean($_POST['fecha_decision'] ?? '');
$fechaReconsideracion = clean($_POST['fecha_reconsideracion'] ?? ''); $observaciones = cleanText($_POST['observaciones'] ?? '');
$stmt = $pdo->prepare("     INSERT INTO caso_debido_proceso (         caso_id,         notificacion_inicio,         fecha_notificacion_inicio,         derecho_descargos,         fecha_descargos,         se_escucho_estudiante,         se_informo_apoderado,         decision_fundada,         fecha_decision,         derecho_reconsideracion,         fecha_reconsideracion,         observaciones     ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)     ON DUPLICATE KEY UPDATE         notificacion_inicio = VALUES(notificacion_inicio),         fecha_notificacion_inicio = VALUES(fecha_notificacion_inicio),         derecho_descargos = VALUES(derecho_descargos),         fecha_descargos = VALUES(fecha_descargos),         se_escucho_estudiante = VALUES(se_escucho_estudiante),         se_informo_apoderado = VALUES(se_informo_apoderado),         decision_fundada = VALUES(decision_fundada),         fecha_decision = VALUES(fecha_decision),         derecho_reconsideracion = VALUES(derecho_reconsideracion),         fecha_reconsideracion = VALUES(fecha_reconsideracion),         observaciones = VALUES(observaciones) ");
$stmt->execute([
    $casoId,
    $data['notificacion_inicio'],
    $fechaNotificacion !== '' ? $fechaNotificacion : null,
    $data['derecho_descargos'],
    $fechaDescargos !== '' ? $fechaDescargos : null,     $data['se_escucho_estudiante'],
    $data['se_informo_apoderado'],
    $data['decision_fundada'],
    $fechaDecision !== '' ? $fechaDecision : null,
    $data['derecho_reconsideracion'],
    $fechaReconsideracion !== '' ? $fechaReconsideracion : null,
    $observaciones !== '' ? $observaciones : null,
]);
$stmt = $pdo->prepare("     INSERT INTO caso_historial (         caso_id,         tipo_evento,         titulo,         detalle,         user_id     ) VALUES (?, ?, ?, ?, ?)
");
$stmt->execute([
