    'seguridad_familiar',
    'otra'
];
$estadosPermitidos = [
    'registrado',
    'en_revision',
    'resuelto',
    'derivado'
];
$involucra = isset($_POST['involucra_dispositivo']) ? 1 : 0;
$tipoDispositivo = clean($_POST['tipo_dispositivo'] ?? '');
$tipoUso = clean($_POST['tipo_uso'] ?? '');
$descripcionHecho = cleanText($_POST['descripcion_hecho'] ?? '');
$existeEvidencia = isset($_POST['existe_evidencia_digital']) ? 1 : 0;
$evidenciaResguardada = isset($_POST['evidencia_resguardada']) ? 1 : 0;
$medidaResguardo = cleanText($_POST['medida_resguardo'] ?? '');
$excepcion = clean($_POST['excepcion_aplicable'] ?? 'ninguna');
$fundamentoExcepcion = cleanText($_POST['fundamento_excepcion'] ?? '');
$adultoResponsable = clean($_POST['adulto_responsable'] ?? '');
$estado = clean($_POST['estado'] ?? 'registrado'); $observaciones = cleanText($_POST['observaciones'] ?? '');
if (!in_array($tipoUso, $tiposUsoPermitidos, true)) {
    $tipoUso = null;
} if (!in_array($excepcion, $excepcionesPermitidas, true)) {     $excepcion = 'ninguna';
}
if (!in_array($estado, $estadosPermitidos, true)) {
    $estado = 'registrado';
}
$stmt = $pdo->prepare("     INSERT INTO caso_moviles (         caso_id,         involucra_dispositivo,         tipo_dispositivo,         tipo_uso,         descripcion_hecho,         existe_evidencia_digital,         evidencia_resguardada,         medida_resguardo,         excepcion_aplicable,         fundamento_excepcion,         adulto_responsable,         estado,         observaciones     ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)     ON DUPLICATE KEY UPDATE
        involucra_dispositivo = VALUES(involucra_dispositivo),         tipo_dispositivo = VALUES(tipo_dispositivo),         tipo_uso = VALUES(tipo_uso),         descripcion_hecho = VALUES(descripcion_hecho),         existe_evidencia_digital = VALUES(existe_evidencia_digital),         evidencia_resguardada = VALUES(evidencia_resguardada),         medida_resguardo = VALUES(medida_resguardo),         excepcion_aplicable = VALUES(excepcion_aplicable),         fundamento_excepcion = VALUES(fundamento_excepcion),         adulto_responsable = VALUES(adulto_responsable),         estado = VALUES(estado),         observaciones = VALUES(observaciones)
");
$stmt->execute([
