23.1 — Crear archivo nuevo
Ruta:
core/AnalisisCasoBuilder.php
PHP
<?php declare(strict_types=1);
final class AnalisisCasoBuilder
{     public static function construir(PDO $pdo, int $casoId): array
    {
        $stmt = $pdo->prepare("
            SELECT 
                c.*,                 da.nombre AS area_denuncia,                 das.nombre AS aspecto_denuncia,
                f.nombre AS falta_nombre,
                f.gravedad AS falta_gravedad             FROM casos c
            LEFT JOIN denuncia_aspectos das ON das.id = c.denuncia_aspecto_id
            LEFT JOIN denuncia_areas da ON da.id = das.area_id
            LEFT JOIN faltas f ON f.id = c.falta_id             WHERE c.id = ?
            LIMIT 1
        ");
        $stmt->execute([$casoId]);
        $caso = $stmt->fetch(PDO::FETCH_ASSOC);
        if (!$caso) {             throw new RuntimeException('Caso no encontrado.');         }
        $participantes = self::fetchAll($pdo, "
            SELECT rol_en_caso, tipo_persona, nombre_referencial, run, identidad_
            FROM caso_participantes             WHERE caso_id = ?
            ORDER BY id ASC
        ", [$casoId]);
        $declaraciones = self::fetchAll($pdo, "
            SELECT tipo_declarante, nombre_declarante, calidad_procesal, fecha_de             FROM caso_declaraciones             WHERE caso_id = ?
            ORDER BY fecha_declaracion ASC
        ", [$casoId]);
        $medidas = self::fetchAll($pdo, "
            SELECT cm.tipo, mc.nombre, cm.estado, cm.fecha_aplicacion, cm.fundame
            FROM caso_medidas cm
            INNER JOIN medidas_catalogo mc ON mc.id = cm.medida_id             WHERE cm.caso_id = ?
            ORDER BY cm.id ASC
        ", [$casoId]);
        $debidoProceso = self::fetchOne($pdo, "
            SELECT *
            FROM caso_debido_proceso             WHERE caso_id = ?
            LIMIT 1
        ", [$casoId]);
        $aulaSegura = self::fetchOne($pdo, "
            SELECT *
            FROM aula_segura_procedimientos             WHERE caso_id = ?
            LIMIT 1
        ", [$casoId]);
        $moviles = self::fetchOne($pdo, "
            SELECT *
            FROM caso_moviles             WHERE caso_id = ?
            LIMIT 1         ", [$casoId]);
        return [
            'caso' => $caso,
            'participantes' => $participantes,
            'declaraciones' => $declaraciones,
            'medidas' => $medidas,
            'debido_proceso' => $debidoProceso,
            'aula_segura' => $aulaSegura,
            'moviles' => $moviles,
        ];     }
    private static function fetchAll(PDO $pdo, string $sql, array $params): array
    {
        $stmt = $pdo->prepare($sql);         $stmt->execute($params);         return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
    private static function fetchOne(PDO $pdo, string $sql, array $params): array
    {
        $stmt = $pdo->prepare($sql);         $stmt->execute($params);         return $stmt->fetch(PDO::FETCH_ASSOC) ?: [];
    }
}
