PHP
<?php declare(strict_types=1);
final class IAService
{
    public static function analizarCasoNormativo(array $expediente): string
    {
        $apiKey = getenv('ANTHROPIC_API_KEY');
        if (!$apiKey) {             return 'API Key no configurada.';         }
        $prompt = self::promptNormativo($expediente);
        $payload = [
            'model' => 'claude-3-5-sonnet-20241022',
            'max_tokens' => 1800,
            'messages' => [
                [
                    'role' => 'user',
                    'content' => $prompt
                ]
            ]
        ];
        $ch = curl_init('https://api.anthropic.com/v1/messages');
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => json_encode($payload),
            CURLOPT_HTTPHEADER => [
                'Content-Type: application/json',
                'x-api-key: ' . $apiKey,
                'anthropic-version: 2023-06-01',
            ],
            CURLOPT_TIMEOUT => 45,
        ]);
        $response = curl_exec($ch);
        if ($response === false) {             return 'Error de conexión IA: ' . curl_error($ch);         }
        $data = json_decode($response, true);
        return $data['content'][0]['text'] ?? 'Sin respuesta IA.';
    }
    private static function promptNormativo(array $e): string
    {         return "
Actúa como asistente técnico de convivencia escolar en Chile. Debes analizar un expediente escolar desde una perspectiva prudente, normativa y 
IMPORTANTE:
- No reemplazas la decisión del establecimiento.
- No inventes hechos.
- No determines culpabilidad.
- Solo entrega análisis de apoyo.
- Seńala riesgos, vacíos y cautelas.
EXPEDIENTE:
" . json_encode($e, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT) . " Responde con esta estructura:
1. Síntesis objetiva del caso
2. Clasificación preliminar de la denuncia
3. Aspectos de convivencia comprometidos
4. Riesgos normativos o procedimentales
5. Revisión de medidas registradas
6. Revisión de debido proceso
7. Revisión de Aula Segura, si aplica
8. Revisión de dispositivos móviles/evidencia digital, si aplica
9. Diligencias o registros faltantes
10. Recomendaciones prudentes para el equipo de convivencia
Lenguaje profesional, claro y útil para expediente interno.
";
    }
}
