Vamos con el siguiente 
Sigue la Fase 25 — Alertas críticas automáticas.
Objetivo: que el sistema avise riesgos sin esperar que el usuario revise todo manualmente.
Debemos detectar:
   casos sin clasificación casos con Aula Segura activo casos con vencimiento de plazo casos con móviles/evidencia digital casos sin debido proceso casos graves sin medidas registradas Orden de trabajo
25.1 Crear tabla alertas_sistema
25.2 Crear generador automático de alertas 25.3 Mostrar alertas en dashboard directivo
25.4 Mostrar alertas dentro del expediente
25.5 Permitir marcar alerta como revisada
25.1 SQL base
Ejecuta primero:
SQL
CREATE TABLE IF NOT EXISTS alertas_sistema (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     caso_id INT UNSIGNED NULL,     tipo VARCHAR(80) NOT NULL,
    severidad ENUM('baja','media','alta','critica') NOT NULL DEFAULT 'media',     titulo VARCHAR(180) NOT NULL,     mensaje TEXT NULL,     estado ENUM('pendiente','revisada','descartada') NOT NULL DEFAULT 'pendiente     fecha_alerta DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,     revisada_por INT UNSIGNED NULL,     fecha_revision DATETIME NULL,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_alertas_colegio (colegio_id),
    INDEX idx_alertas_caso (caso_id),
    INDEX idx_alertas_estado (estado),
    INDEX idx_alertas_severidad (severidad),
    CONSTRAINT fk_alertas_caso         FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
Después seguimos con el archivo: core/AlertasService.php

Procede 
Pensado durante unos segundos
Perfecto. Seguimos con Fase 25.2 — Generador automático de alertas.
25.2 Crear core/AlertasService.php
PHP
<?php declare(strict_types=1);
final class AlertasService
{     public static function generar(PDO $pdo, int $colegioId): void
    {         self::casosSinClasificacion($pdo, $colegioId);         self::aulaSeguraActiva($pdo, $colegioId);         self::aulaSeguraPlazos($pdo, $colegioId);         self::movilesEvidenciaDigital($pdo, $colegioId);         self::casosSinDebidoProceso($pdo, $colegioId);         self::casosGravesSinMedidas($pdo, $colegioId);
    }
    private static function crear(         PDO $pdo,         int $colegioId,         ?int $casoId,         string $tipo,         string $severidad,         string $titulo,         string $mensaje
    ): void {
        $hashTipo = $tipo . '_' . ($casoId ?? 0);
        $stmt = $pdo->prepare("
            SELECT id
            FROM alertas_sistema             WHERE colegio_id = ?
              AND tipo = ?
              AND caso_id <=> ?
              AND estado = 'pendiente'
            LIMIT 1
        ");
        $stmt->execute([$colegioId, $tipo, $casoId]);
        if ($stmt->fetchColumn()) {             return;         }
        $stmt = $pdo->prepare("             INSERT INTO alertas_sistema (                 colegio_id,                 caso_id,                 tipo,                 severidad,                 titulo,                 mensaje             ) VALUES (?, ?, ?, ?, ?, ?)
        ");
        $stmt->execute([
            $colegioId,
            $casoId,
            $tipo,
            $severidad,
            $titulo,             $mensaje
        ]);     }
    private static function casosSinClasificacion(PDO $pdo, int $colegioId): void
    {
        $stmt = $pdo->prepare("
            SELECT id, numero_caso
            FROM casos
            WHERE colegio_id = ?
              AND denuncia_aspecto_id IS NULL
              AND estado <> 'cerrado'         ");
        $stmt->execute([$colegioId]);
        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $c) {             self::crear(                 $pdo,
                $colegioId,
                (int)$c['id'],
                'caso_sin_clasificacion',                 'media',
                'Caso sin clasificación',
                'El caso ' . $c['numero_caso'] . ' no tiene clasificación de denu
            );
        }     }
    private static function aulaSeguraActiva(PDO $pdo, int $colegioId): void
    {
        $stmt = $pdo->prepare("
            SELECT c.id, c.numero_caso
            FROM aula_segura_procedimientos asp
            INNER JOIN casos c ON c.id = asp.caso_id             WHERE c.colegio_id = ?
              AND asp.aplica = 1
              AND asp.estado NOT IN ('cerrado','resuelto')
        ");
        $stmt->execute([$colegioId]);
        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $c) {             self::crear(                 $pdo,
                $colegioId,
                (int)$c['id'],
                'aula_segura_activa',
                'alta',
                'Procedimiento Aula Segura activo',
                'El caso ' . $c['numero_caso'] . ' registra aplicación de Aula Se
            );
        }     }
    private static function aulaSeguraPlazos(PDO $pdo, int $colegioId): void
    {
        $stmt = $pdo->prepare("
            SELECT c.id, c.numero_caso, asp.fecha_limite_resolucion, asp.fecha_li
            FROM aula_segura_procedimientos asp
            INNER JOIN casos c ON c.id = asp.caso_id             WHERE c.colegio_id = ?
              AND asp.aplica = 1
              AND asp.estado NOT IN ('cerrado','resuelto')
        ");
        $stmt->execute([$colegioId]);         $hoy = new DateTimeImmutable('today');
        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $r) {             if (!empty($r['fecha_limite_resolucion'])) {
                $limite = new DateTimeImmutable($r['fecha_limite_resolucion']);
                $dias = (int)$hoy->diff($limite)->format('%r%a');
                if ($dias < 0) {                     self::crear(                         $pdo,
                        $colegioId,
                        (int)$r['id'],
                        'aula_segura_resolucion_vencida',
                        'critica',
                        'Plazo Aula Segura vencido',
                        'El caso ' . $r['numero_caso'] . ' tiene vencido el plazo
                    );
                } elseif ($dias <= 2) {
                    self::crear(                         $pdo,
                        $colegioId,
                        (int)$r['id'],
                        'aula_segura_resolucion_por_vencer',
                        'alta',
                        'Plazo Aula Segura por vencer',
                        'El caso ' . $r['numero_caso'] . ' tiene plazo de resoluc
                    );
                }             }
            if (!empty($r['fecha_limite_reconsideracion'])) {
                $limite = new DateTimeImmutable($r['fecha_limite_reconsideracion
                $dias = (int)$hoy->diff($limite)->format('%r%a');
                if ($dias < 0) {                     self::crear(                         $pdo,
                        $colegioId,
                        (int)$r['id'],
                        'aula_segura_reconsideracion_vencida',
                        'alta',
                        'Plazo de reconsideración vencido',
                        'El caso ' . $r['numero_caso'] . ' tiene vencido el plazo
                    );
                }
            }
        }     }
    private static function movilesEvidenciaDigital(PDO $pdo, int $colegioId): vo
    {
        $stmt = $pdo->prepare("
            SELECT c.id, c.numero_caso, cm.existe_evidencia_digital, cm.evidencia
            FROM caso_moviles cm
            INNER JOIN casos c ON c.id = cm.caso_id
            WHERE c.colegio_id = ?
              AND cm.involucra_dispositivo = 1
              AND c.estado <> 'cerrado'
        ");
        $stmt->execute([$colegioId]);
        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $r) {             if ((int)$r['existe_evidencia_digital'] === 1 && (int)$r['evidencia_r                 self::crear(                     $pdo,
                    $colegioId,
                    (int)$r['id'],
                    'evidencia_digital_no_resguardada',                     'alta',
                    'Evidencia digital no resguardada',
                    'El caso ' . $r['numero_caso'] . ' registra evidencia digital
                );
            }
        }     }
    private static function casosSinDebidoProceso(PDO $pdo, int $colegioId): void
    {
        $stmt = $pdo->prepare("
            SELECT c.id, c.numero_caso
            FROM casos c
            LEFT JOIN caso_debido_proceso dp ON dp.caso_id = c.id             WHERE c.colegio_id = ?
              AND c.estado <> 'cerrado'               AND (                     dp.id IS NULL                     OR dp.notificacion_inicio = 0
                    OR dp.derecho_descargos = 0
                    OR dp.decision_fundada = 0
              )
        ");
        $stmt->execute([$colegioId]);
        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $c) {             self::crear(                 $pdo,
                $colegioId,
                (int)$c['id'],
                'debido_proceso_incompleto',                 'alta',
                'Debido proceso incompleto',
                'El caso ' . $c['numero_caso'] . ' no tiene completo el control m
            );
        }     }
    private static function casosGravesSinMedidas(PDO $pdo, int $colegioId): void
    {
        $stmt = $pdo->prepare("
            SELECT c.id, c.numero_caso, f.gravedad
            FROM casos c
            INNER JOIN faltas f ON f.id = c.falta_id
            LEFT JOIN caso_medidas cm ON cm.caso_id = c.id             WHERE c.colegio_id = ?
              AND c.estado <> 'cerrado'
              AND f.gravedad IN ('grave','gravísima','gravisima')
              AND cm.id IS NULL
        ");
        $stmt->execute([$colegioId]);
        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $c) {             self::crear(                 $pdo,
                $colegioId,
                (int)$c['id'],
                'caso_grave_sin_medidas',
                'critica',
                'Caso grave sin medidas registradas',
                'El caso ' . $c['numero_caso'] . ' tiene falta grave asociada, pe             );
        }
    }
}
