PHP
<?php declare(strict_types=1);
require_once dirname(__DIR__, 2) . '/config/app.php'; require_once dirname(__DIR__, 2) . '/core/DB.php'; require_once dirname(__DIR__, 2) . '/core/Auth.php'; require_once dirname(__DIR__, 2) . '/core/helpers.php';
Auth::requireLogin();
$pdo = DB::conn();
$user = Auth::user();
$colegioId = (int)($user['colegio_id'] ?? 0);
$userId = (int)($user['id'] ?? 0);
$alertaId = cleanInt($_GET['id'] ?? 0);
$casoId = cleanInt($_GET['caso_id'] ?? 0);
$accion = clean($_GET['accion'] ?? 'revisada'); $estados = ['revisada', 'descartada'];
if ($alertaId <= 0 || $casoId <= 0 || !in_array($accion, $estados, true)) {     exit('Datos inválidos.'); }
$stmt = $pdo->prepare("
    UPDATE alertas_sistema     SET estado = ?,         revisada_por = ?,         fecha_revision = NOW()     WHERE id = ?
      AND colegio_id = ?
      AND caso_id = ?
");
$stmt->execute([
    $accion,
    $userId > 0 ? $userId : null,
    $alertaId,
    $colegioId,
    $casoId
]);
header('Location: ' . APP_URL . '/modules/denuncias/ver.php?id=' . $casoId); exit;
