CREATE TABLE IF NOT EXISTS informe_folios (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     caso_id INT UNSIGNED NOT NULL,     tipo_informe VARCHAR(80) NOT NULL DEFAULT 'directivo',     folio VARCHAR(80) NOT NULL UNIQUE,     codigo_validacion VARCHAR(120) NOT NULL UNIQUE,     emitido_por INT UNSIGNED NULL,     fecha_emision DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,     estado ENUM('vigente','anulado') NOT NULL DEFAULT 'vigente',
    INDEX idx_if_colegio (colegio_id),
    INDEX idx_if_caso (caso_id),
    CONSTRAINT fk_if_caso
        FOREIGN KEY (caso_id) REFERENCES casos(id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
2. Crear helper de folios Ruta:
core/FolioService.php
PHP
<?php declare(strict_types=1);
final class FolioService
{
    public static function obtenerOCrear(         PDO $pdo,         int $colegioId,         int $casoId,         int $userId,         string $tipo = 'directivo'     ): array {
        $stmt = $pdo->prepare("             SELECT *
            FROM informe_folios             WHERE colegio_id = ?
              AND caso_id = ?
              AND tipo_informe = ?
              AND estado = 'vigente'
            ORDER BY id DESC
            LIMIT 1
        ");
        $stmt->execute([$colegioId, $casoId, $tipo]);         $folio = $stmt->fetch(PDO::FETCH_ASSOC);
        if ($folio) {             return $folio;         }
        $folioTexto = 'METIS-' . strtoupper($tipo) . '-' . date('Y') . '-' . str_
        $codigo = hash('sha256', $folioTexto . '|' . $colegioId . '|' . $casoId 
        $stmt = $pdo->prepare("             INSERT INTO informe_folios (                 colegio_id,                 caso_id,                 tipo_informe,                 folio,                 codigo_validacion,                 emitido_por             ) VALUES (?, ?, ?, ?, ?, ?)
        ");
        $stmt->execute([
            $colegioId,
            $casoId,
            $tipo,
            $folioTexto,
            $codigo,
            $userId > 0 ? $userId : null
        ]);
        $stmt = $pdo->prepare("             SELECT *
            FROM informe_folios             WHERE id = ?
        ");
        $stmt->execute([(int)$pdo->lastInsertId()]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }
}
