) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS docentes (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     colegio_id INT UNSIGNED NOT NULL,     run VARCHAR(20) NULL,
    nombres VARCHAR(120) NOT NULL,     apellido_paterno VARCHAR(120) NULL,     apellido_materno VARCHAR(120) NULL,     cargo VARCHAR(120) NULL,     email VARCHAR(150) NULL,     estado ENUM('activo','inactivo','baja') NOT NULL DEFAULT 'activo',     observaciones TEXT NULL,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_docentes_colegio (colegio_id),
    INDEX idx_docentes_run (run),
    INDEX idx_docentes_estado (estado)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS alumno_apoderado (     id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,     alumno_id INT UNSIGNED NOT NULL,     apoderado_id INT UNSIGNED NOT NULL,     parentesco VARCHAR(80) NULL,     es_titular TINYINT(1) NOT NULL DEFAULT 0,     activo TINYINT(1) NOT NULL DEFAULT 1,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE KEY uq_alumno_apoderado (alumno_id, apoderado_id),
    INDEX idx_aa_alumno (alumno_id),
    INDEX idx_aa_apoderado (apoderado_id),
    CONSTRAINT fk_aa_alumno
        FOREIGN KEY (alumno_id) REFERENCES alumnos(id)
        ON DELETE RESTRICT         ON UPDATE CASCADE,
    CONSTRAINT fk_aa_apoderado
        FOREIGN KEY (apoderado_id) REFERENCES apoderados(id)
        ON DELETE RESTRICT
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
